/**
 * @fileoverview Badge view — DOM setup / teardown and rendering.
 * @module module/Badge/view
 */

import { CLS, PART } from './constants.js';

// ═══════════════════════════════════════
//  State Machine Effects
// ═══════════════════════════════════════

export const SM_EFFECTS = {
    visible({ root }) {
        root.removeClass(CLS.HIDDEN);
    },
    hidden({ root }) {
        root.addClass(CLS.HIDDEN);
    },
};

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Build the badge DOM structure inside the root element.
 *
 * @param {Elements} root — razyui-wrapped root element
 * @param {object} config — badge configuration
 * @returns {{ contentEl: Elements }}
 */
export function setupDOM(root, config) {
    const { size, variant, pill, dot } = config;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    // Size variant
    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    // Color variant
    const variantMap = {
        success: PART.SUCCESS,
        warning: PART.WARNING,
        error:   PART.ERROR,
        info:    PART.INFO,
    };
    if (variantMap[variant]) {
        variantMap[variant].apply(root);
    }

    // Pill shape
    if (pill) {
        root.addClass(CLS.PILL);
    }

    // Variant → dot color map (inline style to override token defaults)
    const variantDotColor = {
        success: 'var(--bd-success-text)',
        warning: 'var(--bd-warning-text)',
        error:   'var(--bd-error-text)',
        info:    'var(--bd-info-text)',
    };

    // Content element
    let contentEl;
    if (dot) {
        contentEl = PART.DOT.create();
        root.append(contentEl);
        if (variantDotColor[variant]) {
            root.css('--bd-dot-bg', variantDotColor[variant]);
        }
    } else {
        contentEl = PART.LABEL.create();
        root.append(contentEl);
    }

    // Hidden state
    if (config.hidden) {
        root.addClass(CLS.HIDDEN);
    }

    return { contentEl };
}

// ═══════════════════════════════════════
//  DOM Teardown
// ═══════════════════════════════════════

/**
 * Remove all attributes, roles, and classes added by the Badge.
 *
 * @param {Elements} root
 */
export function cleanupDOM(root) {
    root.removeClass(
        CLS.ROOT, CLS.HIDDEN, CLS.PILL,
        PART.ROOT, PART.SM_ROOT, PART.LG_ROOT,
        PART.SUCCESS, PART.WARNING, PART.ERROR, PART.INFO,
    );

    const el = root[0];
    while (el.firstChild) el.removeChild(el.firstChild);
}
