/**
 * @fileoverview Badge constants — CSS classes, selectors, defaults, JIT parts.
 * @module module/Badge/constants
 */

import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:     'badge',
    DOT:      'badge-dot',
    COUNT:    'badge-count',
    LABEL:    'badge-label',
    HIDDEN:   'is-hidden',
    PILL:     'badge-pill',
});

/** DOM selectors */
export const SEL = Object.freeze({
    ROOT:  '.badge',
    DOT:   '.badge-dot',
    COUNT: '.badge-count',
    LABEL: '.badge-label',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    variant: 'default',    // default | success | warning | error | info
    size: 'md',            // sm | md | lg
    pill: false,           // rounded-pill shape
    dot: false,            // dot indicator mode (no text)
    count: null,           // numeric count badge
    max: 99,               // max count display (99+)
    text: '',              // text content
    hidden: false,         // initially hidden
    onChange: null,         // callback when value changes
});

/** Semantic PART entities for JIT styling. */
export const PART = defineParts('Badge', {
    ROOT:    { class: 'badge-container', aliases: ['badge', 'root', 'container'] },
    DOT:     { class: 'badge-dot', aliases: ['dot', 'indicator'], tag: 'span' },
    COUNT:   { class: 'badge-count', aliases: ['count', 'number'] },
    LABEL:   { class: 'badge-label', aliases: ['label', 'text'], tag: 'span' },
    SM_ROOT: { class: 'badge-container-sm', aliases: ['sm'] },
    LG_ROOT: { class: 'badge-container-lg', aliases: ['lg'] },
    PILL:    { class: 'badge-pill', aliases: ['pill'] },
    SUCCESS: { class: 'badge-success', aliases: ['success'] },
    WARNING: { class: 'badge-warning', aliases: ['warning'] },
    ERROR:   { class: 'badge-error', aliases: ['error'] },
    INFO:    { class: 'badge-info', aliases: ['info'] },
});

PART.ROOT.jit    = 'inline-flex items-center justify-center [font-family:var(--bd-font-stack)] text-[var(--bd-font-size)] font-semibold fg-[var(--bd-text)] bg-[var(--bd-bg)] [border:1px_solid_var(--bd-border)] rounded-[var(--bd-radius)] px-[var(--bd-px)] py-[var(--bd-py)] [line-height:1] [white-space:nowrap] [vertical-align:middle] gap-[var(--bd-gap)] [min-width:var(--bd-min-w)] [transition:opacity_.2s_ease,transform_.2s_ease] {is-hidden}:opacity-0 {is-hidden}:[transform:scale(0.5)] {is-hidden}:pointer-events-none';
PART.DOT.jit     = 'inline-block w-[var(--bd-dot-size)] h-[var(--bd-dot-size)] rounded-full bg-[var(--bd-dot-bg)] shadow-[0_0_0_2px_currentColor] [outline:2px_solid_var(--bd-dot-bg)] [outline-offset:2px]';
PART.COUNT.jit   = 'inline-flex items-center justify-center text-[var(--bd-font-size)] font-bold fg-[var(--bd-text)]';
PART.LABEL.jit   = 'inline-block fg-[var(--bd-text)]';
PART.PILL.jit    = '[border-radius:var(--bd-radius)]';
PART.SM_ROOT.jit = '[--bd-font-size:var(--bd-sm-font-size)] [--bd-px:var(--bd-sm-px)] [--bd-py:var(--bd-sm-py)] [--bd-min-w:var(--bd-sm-min-w)]';
PART.LG_ROOT.jit = '[--bd-font-size:var(--bd-lg-font-size)] [--bd-px:var(--bd-lg-px)] [--bd-py:var(--bd-lg-py)] [--bd-min-w:var(--bd-lg-min-w)]';
PART.SUCCESS.jit = '[--bd-bg:var(--bd-success-bg)] [--bd-text:var(--bd-success-text)] [--bd-border:var(--bd-success-border)]';
PART.WARNING.jit = '[--bd-bg:var(--bd-warning-bg)] [--bd-text:var(--bd-warning-text)] [--bd-border:var(--bd-warning-border)]';
PART.ERROR.jit   = '[--bd-bg:var(--bd-error-bg)] [--bd-text:var(--bd-error-text)] [--bd-border:var(--bd-error-border)]';
PART.INFO.jit    = '[--bd-bg:var(--bd-info-bg)] [--bd-text:var(--bd-info-text)] [--bd-border:var(--bd-info-border)]';
